import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Quote: simplest cases (edge cases) ---
  it("empty item list → premium 5 G (only processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result.results[0]).toEqual({ premium: 5 });
  });

  // --- Quote: base premiums for main items ---
  it("single sword (steel, ench 0, not cursed), new customer's first contract → 100 base + 10 first-insurance + 5 fee = 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 115 });
  });
  it.todo("single amulet → 60 base + 6 first-insurance + 5 fee = 71 G");
  it.todo("single staff → 80 base + 8 first-insurance + 5 fee = 93 G");
  it.todo("single potion → 40 base + 4 first-insurance + 5 fee = 49 G");

  // --- Quote: components and blocks ---
  it.todo("2 runes → 50 G base + 5 first-insurance + 5 fee = 60 G");
  it.todo("3 runes → 60 G base (block applies) + 6 first-insurance + 5 fee = 71 G");
  it.todo("4 runes → 100 G base (no block — block requires exactly 3) + 10 first-insurance + 5 fee = 115 G");
  it.todo("7 runes → 175 G base + 18 first-insurance (rounded up) + 5 fee = 198 G");
  it.todo("2 runes + 1 moonstone → 75 G base (no block: different types)");
  it.todo("3 runes + 3 moonstones → 120 G base (two separate blocks)");

  // --- Quote: item-specific modifiers ---
  it.todo("cursed sword adds 50% risk surcharge to the cursed item only");
  it.todo("highly enchanted item (ench ≥ 5) adds 30% risk surcharge");
  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
  it.todo("cursed sword with enchantment 5 → both surcharges apply");

  // --- Quote: policy-wide modifiers ---
  it.todo("long-standing customer (≥ 2 years) receives 20% loyalty discount on policy base");
  it.todo("customer with exactly 2 years → loyalty discount applies");
  it.todo("first insurance carries 10% initial assessment surcharge per item");
  it.todo("follow-up contract (each contract after the first) gets 15% discount");
  it.todo("5 G processing fee added to every premium");

  // --- Quote: scope clarifications (❓) ---
  it.todo("cursed sword + plain amulet → 100+60=160 base, +50 curse on sword, +21 first-insurance, -15 follow-up doesn't apply (first contract) → 210 G before fee ; example: cursed sword (100) + plain amulet (60) → 210 G before further modifiers and fee");
  it.todo("first-insurance surcharge applies per item even for follow-up contracts");

  // --- Quote: rounding (in MHPCO's favor = round premium up) ---
  it.todo("premium calculation 197.5 G → 198 G (rounded up)");
  it.todo("intermediate amounts kept as fractions; only final premium rounded");

  // --- Quote: error cases ---
  it.todo("quote includes item with unknown type → CLI exits non-zero, error to stderr, no results to stdout");

  // --- Quote: integration examples ---
  it.todo("newcomer (0 years, no prev contract) with cursed sword (steel, ench 3) → 165 G");
  it.todo("long-standing customer (3 years), 2nd quote, cursed sword (steel, ench 7) → 160 G");

  // --- Claim: standard reimbursement ---
  it.todo("regular sword (steel, ench 3) damaged 500 G → payout 400 G (500 - 100 deductible)");
  it.todo("rune (insurance value 250 G) damaged 200 G → payout 100 G");

  // --- Claim: enchantment threshold ---
  it.todo("steel sword ench 9, damage 1000 G → payout 400 G (50% then deductible)");
  it.todo("dragon-material sword ench 8, damage 1000 G → payout 400 G (ench rule wins, then deductible)");

  // --- Claim: dragon material ---
  it.todo("dragon-material sword ench 5, damage 800 G → payout 700 G (full reimbursement, then deductible)");

  // --- Claim: both clauses ---
  it.todo("dragon-material sword ench 9, damage 1000 G → payout 400 G (50% wins, then deductible)");

  // --- Claim: deductible per damage event ---
  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible per item)");

  // --- Claim: multiple items of same type ---
  it.todo("two-sword policy → insurance sum 2000 G, cap 4000 G");
  it.todo("two sword damages on two-sword policy → each treated as separate damage with own deductible");
  it.todo("damages array has more entries of a type than policy covers → CLI exits non-zero, claim rejected");

  // --- Claim: cap based on insurance values ---
  it.todo("sword + amulet policy → insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword (premium 165 G with modifiers) → cap 2000 G (based on unmodified insurance value)");
  it.todo("sword + 3 runes (block) → insurance sum 1750 G (block discount doesn't affect insurance sum)");

  // --- Claim: cap exhaustion across successive claims ---
  it.todo("sword cap 2000 G, first claim 1500 G damage → payout 1400 G, cap remaining 600 G");
  it.todo("sword cap 2000 G, second claim 1500 G after first exhausted to 600 → payout 600 G, cap remaining 0");

  // --- Claim: rounding (in MHPCO's favor = round payout down) ---
  it.todo("payout calculation 350.5 G → 350 G (rounded down)");

  // --- Claim: error cases ---
  it.todo("claim references damage entry whose item is not part of policy → CLI exits non-zero, error to stderr");
  it.todo("claim references item with unknown type → CLI exits non-zero, error to stderr");
  it.todo("claim contains damage entry with amount: -200 → CLI exits non-zero, error to stderr");

  // --- CLI / scenario level ---
  it.todo("scenario with single quote step produces results array with one premium");
  it.todo("scenario with quote then claim returns premium then payout + remainingCap");
  it.todo("CLI reads JSON from stdin and writes JSON to stdout");
});

