const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;
const COMPONENT_BASE_PREMIUM = 25;
const BLOCK_SIZE = 3;
const BLOCK_BASE_PREMIUM = 60;

const MAIN_BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_TYPES = new Set(["rune"]);

type Item = { type: string } & Record<string, unknown>;

type QuoteStep = { op: "quote"; items: Array<Item> };

type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Array<QuoteStep>;
};

type QuoteResult = { premium: number };

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const componentsBasePremium = (components: Array<Item>): number => {
  const byType = new Map<string, number>();
  for (const c of components) {
    byType.set(c.type, (byType.get(c.type) ?? 0) + 1);
