const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;
const COMPONENT_BASE_PREMIUM = 25;
const BLOCK_SIZE = 3;
const BLOCK_BASE_PREMIUM = 60;

const MAIN_BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_TYPES = new Set(["rune"]);

type Item = { type: string } & Record<string, unknown>;

type QuoteStep = { op: "quote"; items: Array<Item> };

type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Array<QuoteStep>;
};

type QuoteResult = { premium: number };

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const componentsBasePremium = (components: Array<Item>): number => {
  const byType = new Map<string, number>();
  for (const c of components) {
    byType.set(c.type, (byType.get(c.type) ?? 0) + 1);
  }
  let total = 0;
  for (const count of byType.values()) {
    if (count === BLOCK_SIZE) {
      total += BLOCK_BASE_PREMIUM;
    } else {
      total += count * COMPONENT_BASE_PREMIUM;
    }
  }
  return total;
};

const policyBasePremium = (items: Array<Item>): number => {
  const mains = items.filter((i) => !isComponent(i));
  const components = items.filter(isComponent);
  const mainsTotal = mains.reduce((sum, item) => sum + MAIN_BASE_PREMIUMS[item.type], 0);
  return mainsTotal + componentsBasePremium(components);
};

const quoteStep = (step: QuoteStep): QuoteResult => {
  const policyBase = policyBasePremium(step.items);
  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
  return { premium: Math.ceil(policyBase + firstInsurance + PROCESSING_FEE) };
};

export const runScenario = (scenario: Scenario): { results: Array<QuoteResult> } => {
  return { results: scenario.steps.map(quoteStep) };
};

