21	  staff: { basePremium: 80, insuranceValue: 800 },
22	  potion: { basePremium: 40, insuranceValue: 400 },
23	};
24	
25	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
26	
27	type Item = {
28	  type: string;
29	  material?: string;
30	  enchantment?: number;
31	  cursed?: boolean;
32	};
33	
34	type QuoteStep = { op: "quote"; items: Array<Item> };
35	
36	type Damage = { itemType: string; amount: number };
37	type Incident = { cause: string; damages: Array<Damage> };
38	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
39	
40	type Step = QuoteStep | ClaimStep;
41	
42	type Customer = { yearsWithMHPCO: number };
43	
44	type Scenario = {
45	  customer: Customer;
46	  steps: Array<Step>;
47	};
48	
49	type QuoteResult = { premium: number };
50	type ClaimResult = { payout: number; remainingCap: number };
51	type StepResult = QuoteResult | ClaimResult;
52	
53	type Policy = {
54	  items: Array<Item>;
55	  insuranceSum: number;
56	  remainingCap: number;
57	};
58	
59	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
60	
61	const isKnownItemType = (type: string): boolean =>
62	  type in MAIN_ITEM_INFO || COMPONENT_TYPES.has(type);
63	
64	const validateItems = (items: Array<Item>): void => {
65	  for (const item of items) {
66	    if (!isKnownItemType(item.type)) {
67	      throw new Error(`Unknown item type: ${item.type}`);
68	    }
69	  }
70	};
71	
72	const componentsBasePremium = (components: Array<Item>): number => {
73	  const countsByType = countByType(components, (c) => c.type);
74	  let total = 0;
75	  for (const count of countsByType.values()) {
76	    total += count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * COMPONENT_BASE_PREMIUM;
77	  }
78	  return total;
79	};
80	
81	const policyBasePremium = (items: Array<Item>): number => {
82	  const mains = items.filter((i) => !isComponent(i));
83	  const components = items.filter(isComponent);
84	  const mainsTotal = mains.reduce((sum, item) => sum + MAIN_ITEM_INFO[item.type].basePremium, 0);
85	  return mainsTotal + componentsBasePremium(components);
86	};
87	
88	const itemSurcharges = (items: Array<Item>): number => {
89	  let total = 0;
90	  for (const item of items) {
91	    if (isComponent(item)) continue;
92	    const base = MAIN_ITEM_INFO[item.type].basePremium;
93	    if (item.cursed) total += base * CURSE_SURCHARGE_RATE;
94	    const enchantment = item.enchantment ?? 0;
95	    if (enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
96	      total += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
97	    }
98	  }
99	  return total;
100	};
101	
102	const insuranceValueOf = (item: Item): number =>
103	  isComponent(item) ? COMPONENT_INSURANCE_VALUE : MAIN_ITEM_INFO[item.type].insuranceValue;
104	
105	const insuranceSum = (items: Array<Item>): number =>
106	  items.reduce((sum, item) => sum + insuranceValueOf(item), 0);
107	
108	const quoteStep = (
109	  step: QuoteStep,
110	  customer: Customer,
111	  isFollowUpContract: boolean,
112	): { result: QuoteResult; policy: Policy } => {
113	  validateItems(step.items);
114	  const policyBase = policyBasePremium(step.items);
115	  const surcharges = itemSurcharges(step.items);
116	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
117	  const loyaltyDiscount =
118	    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
119	  const followUpDiscount = isFollowUpContract ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
120	  const premium = Math.ceil(
121	    policyBase +
122	      surcharges +
123	      firstInsurance -
124	      loyaltyDiscount -
125	      followUpDiscount +
126	      PROCESSING_FEE,
127	  );
128	  const sum = insuranceSum(step.items);
129	  return {
130	    result: { premium },
131	    policy: { items: step.items, insuranceSum: sum, remainingCap: sum * CAP_MULTIPLIER },
132	  };
133	};
134	
135	const reimbursementFor = (item: Item, damageAmount: number): number => {
136	  const enchantment = item.enchantment ?? 0;
137	  if (enchantment >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD) {
138	    return damageAmount * HIGH_ENCHANTMENT_PAYOUT_RATE;
139	  }
140	  return damageAmount;
141	};
142	
143	const countByType = <T>(entries: Array<T>, key: (e: T) => string): Map<string, number> => {
144	  const counts = new Map<string, number>();
145	  for (const entry of entries) {
146	    const type = key(entry);
147	    counts.set(type, (counts.get(type) ?? 0) + 1);
148	  }
149	  return counts;
150	};
151	
152	const validateDamagesAgainstPolicy = (damages: Array<Damage>, policy: Policy): void => {
153	  const policyCounts = countByType(policy.items, (i) => i.type);
154	  const damageCounts = countByType(damages, (d) => d.itemType);
155	  for (const [itemType, count] of damageCounts) {
156	    const available = policyCounts.get(itemType) ?? 0;
157	    if (count > available) {
158	      throw new Error(
159	        `Claim damages exceed policy coverage for itemType: ${itemType} (claimed ${count}, covered ${available})`,
160	      );
161	    }
162	  }
163	};
164	
165	const validateDamages = (damages: Array<Damage>): void => {
166	  for (const damage of damages) {
167	    if (damage.amount < 0) {
168	      throw new Error(`Damage amount must be non-negative, got ${damage.amount}`);
169	    }
170	  }
171	};
172	
173	const claimStep = (step: ClaimStep, policy: Policy): ClaimResult => {
174	  validateDamages(step.incident.damages);
175	  validateDamagesAgainstPolicy(step.incident.damages, policy);
176	  let payout = 0;
177	  for (const damage of step.incident.damages) {
178	    const item = policy.items.find((i) => i.type === damage.itemType);
179	    if (!item) throw new Error(`Claim references item not in policy: ${damage.itemType}`);
180	    const reimbursement = reimbursementFor(item, damage.amount);
181	    const afterDeductible = Math.max(0, reimbursement - DEDUCTIBLE);
182	    payout += afterDeductible;
183	  }
184	  payout = Math.min(payout, policy.remainingCap);
185	  policy.remainingCap -= payout;
186	  return { payout: Math.floor(payout), remainingCap: policy.remainingCap };
187	};
188	
189	export const runScenario = (scenario: Scenario): { results: Array<StepResult> } => {
190	  let quoteCount = 0;
191	  const policies: Array<Policy> = [];
192	  const results: Array<StepResult> = scenario.steps.map((step, index) => {
193	    if (step.op === "quote") {
194	      const { result, policy } = quoteStep(step, scenario.customer, quoteCount > 0);
195	      quoteCount++;
196	      policies[index] = policy;
197	      return result;
198	    }
199	    const policy = policies[step.policy];
200	    return claimStep(step, policy);
201	  });
202	  return { results };
203	};
